long long solve(std::vector<long long> nums, long long k) {
    if (nums.size() == 1) {
        return 0;
    }

    // Sort the array
    std::sort(nums.begin(), nums.end());

    // Use a sliding window to find the longest subarray that is balanced
    int left = 0;
    long long minRemovals = nums.size(); // Maximum possible removals

    for (int right = 0; right < nums.size(); ++right) {
        // Move left pointer to maintain a window where the max is at right and min is at left
        while (left < right && nums[right] > nums[left] * k) {
            ++left;
        }

        // The current window is [left, right], so the number of elements to remove is (right - left + 1)
        // Wait, no: we want to keep the elements in the window, so the number of elements to remove is (total elements - window size)
        // So, the number of elements to remove is (nums.size() - (right - left + 1))
        long long currentRemovals = nums.size() - (right - left + 1);
        minRemovals = std::min(minRemovals, currentRemovals);
    }

    return minRemovals;
}

